SELECT post_id FROM post_bookmark
WHERE post_id = #{postId} AND member_id = #{memberId}
LIMIT 1

SELECT , false AS liked, (p.deleted_at IS NOT NULL) AS deleted, ,
FROM post_bookmark pb JOIN post p ON p.id = pb.post_id LEFT JOIN member m ON m.id = p.member_id
WHERE pb.member_id = #{memberId} ORDER BY pb.created_at DESC LIMIT #{limit} OFFSET #{offset}
